from typing import List

def solve(n: int, edges: List[List[int]], k: int) -> int:
    if not edges:
        return 0

    max_w = max(edge[2] for edge in edges)
    low = 0
    high = max_w
    answer = max_w

    while low <= high:
        mid = (low + high) // 2
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            if w <= mid:
                adj[u].append(v)
                adj[v].append(u)

        visited = [False] * n
        components = 0

        for i in range(n):
            if not visited[i]:
                components += 1
                stack = [i]
                visited[i] = True
                while stack:
                    node = stack.pop()
                    for nei in adj[node]:
                        if not visited[nei]:
                            visited[nei] = True
                            stack.append(nei)

        if components <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1

    return answer
