def solve(n: int, edges: list[list[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    if not edges:
        return 0
    max_w = edges[-1][2]
    low = 0
    high = max_w
    answer = max_w

    while low <= high:
        mid = (low + high) // 2
        parent = list(range(n))

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            u_root = find(u)
            v_root = find(v)
            if u_root == v_root:
                return
            parent[v_root] = u_root

        for u, v, w in edges:
            if w <= mid:
                union(u, v)

        roots = set()
        for i in range(n):
            roots.add(find(i))
        count = len(roots)

        if count <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1

    return answer
